lir::LirModule make_aarch64_tracked_pointer_field_reload_lir_module() {
  lir::LirModule module;
  module.target_profile = c4c::default_target_profile(c4c::TargetArch::Aarch64);
  module.type_decls.push_back("%struct.ptrbox = type { ptr }");

  lir::LirFunction function;
  function.name = "aarch64_tracked_pointer_field_reload";
  function.signature_text = "define void @aarch64_tracked_pointer_field_reload(ptr %cursor)";
  function.return_type = scalar_type(c4c::TB_VOID);
  function.signature_return_type_ref = lir::LirTypeRef("void");
  c4c::TypeSpec ptr_type{};
  ptr_type.base = c4c::TB_VOID;
  ptr_type.ptr_level = 1;
  function.params.push_back({"%cursor", ptr_type});
  function.signature_params.push_back(lir::LirSignatureParam{
      .name = "%cursor",
      .type = ptr_type,
      .is_byval = false,
  });
  function.signature_param_type_refs.push_back(lir::LirTypeRef("ptr"));
  function.alloca_insts.push_back(lir::LirAllocaOp{
      .result = lir::LirOperand("%lv.box"),
      .type_str = "%struct.ptrbox",
      .count = lir::LirOperand(""),
      .align = 8,
  });

  lir::LirBlock entry;
  entry.id = function.alloc_block();
  entry.label = "entry";
  function.entry = entry.id;
  entry.insts.push_back(lir::LirGepOp{
      .result = lir::LirOperand("%field"),
      .element_type = "%struct.ptrbox",
      .ptr = lir::LirOperand("%lv.box"),
      .indices = {"i32 0", "i32 0"},
  });
  entry.insts.push_back(lir::LirStoreOp{
      .type_str = "ptr",
      .val = lir::LirOperand("%cursor"),
      .ptr = lir::LirOperand("%field"),
  });
  entry.insts.push_back(lir::LirLoadOp{
      .result = lir::LirOperand("%first"),
      .type_str = "ptr",
      .ptr = lir::LirOperand("%field"),
  });
  entry.insts.push_back(lir::LirGepOp{
      .result = lir::LirOperand("%advanced"),
      .element_type = "i8",
      .ptr = lir::LirOperand("%first"),
      .indices = {"i64 16"},
  });
  entry.insts.push_back(lir::LirStoreOp{
      .type_str = "ptr",
      .val = lir::LirOperand("%advanced"),
      .ptr = lir::LirOperand("%field"),
  });
  entry.insts.push_back(lir::LirLoadOp{
      .result = lir::LirOperand("%second"),
      .type_str = "ptr",
      .ptr = lir::LirOperand("%field"),
  });
  entry.insts.push_back(lir::LirGepOp{
      .result = lir::LirOperand("%after_second"),
      .element_type = "i8",
      .ptr = lir::LirOperand("%second"),
      .indices = {"i64 16"},
  });
  entry.terminator = lir::LirRet{
      .value_str = std::nullopt,
      .type_str = "void",
  };
  function.blocks.push_back(std::move(entry));
  module.functions.push_back(std::move(function));
  return module;
}

prepare::PreparedBirModule prepared_with_variadic_entry_formal_stack_homes() {
  auto prepared = prepared_with_variadic_entry_helper_call(true, true, true);
  auto& function = prepared.module.functions.front();
  auto& value_homes = prepared.value_locations.functions.front().value_homes;
  const auto function_name = prepared.control_flow.functions.front().function_name;

  function.params.clear();
  value_homes.clear();

  auto add_param = [&](bir::TypeKind type,
                       std::string name,
                       std::size_t size_bytes,
                       std::size_t align_bytes,
                       bir::AbiValueClass abi_class,
                       std::size_t stack_offset_bytes,
                       std::size_t slot_id,
                       std::size_t value_id) {
    const auto value_name = prepared.names.value_names.intern(name);
    function.params.push_back(bir::Param{
        .type = type,
        .name = std::move(name),
        .size_bytes = size_bytes,
        .align_bytes = align_bytes,
        .abi = register_arg_abi(type, size_bytes, align_bytes, abi_class),
    });
    value_homes.push_back(prepare::PreparedValueHome{
        .value_id = prepare::PreparedValueId{value_id},
        .function_name = function_name,
        .value_name = value_name,
        .kind = prepare::PreparedValueHomeKind::StackSlot,
        .slot_id = prepare::PreparedFrameSlotId{slot_id},
        .offset_bytes = stack_offset_bytes,
        .size_bytes = size_bytes,
        .align_bytes = align_bytes,
    });
  };

  add_param(bir::TypeKind::I1, "fixed.i1", 1, 1, bir::AbiValueClass::Integer, 16, 21, 31);
  add_param(bir::TypeKind::I8, "fixed.i8", 1, 1, bir::AbiValueClass::Integer, 17, 22, 32);
  add_param(bir::TypeKind::I16, "fixed.i16", 2, 2, bir::AbiValueClass::Integer, 18, 23, 33);
  add_param(bir::TypeKind::I32, "fixed.i32", 4, 4, bir::AbiValueClass::Integer, 20, 24, 34);
  add_param(bir::TypeKind::I64, "fixed.i64", 8, 8, bir::AbiValueClass::Integer, 24, 25, 35);
  add_param(bir::TypeKind::Ptr, "fixed.ptr", 8, 8, bir::AbiValueClass::Integer, 32, 26, 36);
  add_param(bir::TypeKind::F32, "fixed.f32", 4, 4, bir::AbiValueClass::Sse, 40, 27, 37);
  add_param(bir::TypeKind::F64, "fixed.f64", 8, 8, bir::AbiValueClass::Sse, 48, 28, 38);

  auto& entry_plan = prepared.variadic_entry_plans.functions.front();
  entry_plan.named_parameter_count = function.params.size();
  entry_plan.named_register_counts.gp = 6;
  entry_plan.named_register_counts.fp = 2;
  return prepared;
}

