int fixed_formal_register_home_feeds_later_scalar_lowering() {
  auto prepared = prepared_with_scalar_fixed_formal_register_home();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context =
      aarch64_codegen::make_function_lowering_context(
          prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);

  if (!diagnostics.empty() || result.visited_operations != 1 ||
      !result.visited_terminator || result.emitted_instructions != 3 ||
      block.instructions.size() != 3) {
    return fail("expected fixed formal publication, scalar multiply, and return without diagnostics");
  }

  const auto* publication =
      std::get_if<aarch64_module::codegen::AssemblerInstructionRecord>(
          &block.instructions.front().target.payload);
  if (publication == nullptr ||
      block.instructions.front().target.family !=
          aarch64_module::codegen::InstructionFamily::Assembler ||
      block.instructions.front().target.selection.status !=
          aarch64_module::codegen::MachineNodeSelectionStatus::Selected ||
      !publication->has_inline_asm_payload ||
      publication->inline_asm_template != "mov w13, w0") {
    return fail("expected fixed formal to publish incoming ABI register into prepared home");
  }

  const auto* scalar =
      std::get_if<aarch64_module::codegen::ScalarInstructionRecord>(
          &block.instructions[1].target.payload);
  if (scalar == nullptr || !scalar->scalar_alu.has_value()) {
    return fail("expected scalar multiply after fixed formal publication");
  }
  const auto lhs =
      std::get_if<aarch64_module::codegen::RegisterOperand>(
          &scalar->scalar_alu->lhs.payload);
  const auto rhs =
      std::get_if<aarch64_module::codegen::RegisterOperand>(
          &scalar->scalar_alu->rhs.payload);
  if (lhs == nullptr || rhs == nullptr ||
      lhs->value_name != prepared.names.value_names.find("%p.x") ||
      rhs->value_name != prepared.names.value_names.find("%p.x") ||
      lhs->reg.index != 13 || rhs->reg.index != 13 ||
      lhs->reg.view != aarch64_abi::RegisterView::W ||
      rhs->reg.view != aarch64_abi::RegisterView::W) {
    return fail("expected scalar multiply to consume prepared fixed-formal home, not stale storage");
  }

  const auto printed = print_route_block(function_cf.function_name, block);
  if (!printed.ok ||
      printed.assembly.find("mul w0, w13, w13") == std::string::npos ||
      printed.assembly.find("mul w0, w20, w20") != std::string::npos) {
    return fail("expected printed scalar multiply to read prepared fixed-formal home");
  }
  return 0;
}

int fixed_formal_register_home_publishes_to_local_slot_before_local_loads() {
  auto prepared = prepared_with_fixed_formal_local_slot_publication();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context =
      aarch64_codegen::make_function_lowering_context(
          prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);

  if (!diagnostics.empty() || result.visited_operations != 5 ||
      !result.visited_terminator || result.emitted_instructions != 6 ||
      block.instructions.size() != 6) {
    return fail("expected formal local-slot store, two loads, call, add, and return without diagnostics: visited=" +
                std::to_string(result.visited_operations) +
                " emitted=" + std::to_string(result.emitted_instructions) +
                " block_size=" + std::to_string(block.instructions.size()) +
                " diagnostics=" + std::to_string(diagnostics.entries.size()) +
                (diagnostics.entries.empty()
                     ? std::string{}
                     : " first=" + diagnostics.entries.front().message));
  }

  const auto* store =
      std::get_if<aarch64_module::codegen::MemoryInstructionRecord>(
          &block.instructions.front().target.payload);
  if (store == nullptr ||
      store->memory_kind != aarch64_module::codegen::MemoryInstructionKind::Store ||
      store->address.base_kind != aarch64_module::codegen::MemoryBaseKind::FrameSlot ||
      store->address.frame_slot_id != prepare::PreparedFrameSlotId{411} ||
      !store->value.has_value() ||
      store->value->kind != aarch64_module::codegen::OperandKind::Register) {
    return fail("expected fixed formal to publish through a selected local-slot store");
  }
  const auto* stored_register =
      std::get_if<aarch64_module::codegen::RegisterOperand>(&store->value->payload);
  if (stored_register == nullptr ||
      stored_register->reg != aarch64_abi::w_register(0) ||
      stored_register->value_name != prepared.names.value_names.find("%p.x")) {
    return fail("expected local-slot store to consume the incoming fixed formal register");
  }

  const auto printed = print_route_block(function_cf.function_name, block);
  if (!printed.ok) {
    return fail("expected fixed-formal local-slot route to print: " +
                printed.diagnostic);
  }
  const auto store_pos = printed.assembly.find("str w0, [sp, #16]");
  const auto first_load_pos = printed.assembly.find("ldr w20, [sp, #16]");
  const auto call_pos = printed.assembly.find("bl clobber_formal");
  const auto second_load_pos = printed.assembly.find("ldr w21, [sp, #16]");
  const auto add_pos = printed.assembly.find("add w0, w20, w21");
  if (store_pos == std::string::npos ||
      first_load_pos == std::string::npos ||
      call_pos == std::string::npos ||
      second_load_pos == std::string::npos ||
      add_pos == std::string::npos ||
      !(store_pos < first_load_pos && first_load_pos < call_pos &&
        call_pos < second_load_pos && second_load_pos < add_pos) ||
      printed.assembly.find("ldr w9, [sp]\n    str w9, [sp, #16]") !=
          std::string::npos) {
    return fail("expected formal register to seed the local slot before local loads: " +
                printed.assembly);
  }

  auto missing_authority = prepared_with_fixed_formal_local_slot_publication();
  const auto missing_param_name =
      missing_authority.names.value_names.find("%p.x");
  missing_authority.value_locations.functions.front().value_homes.clear();
  const auto& missing_function_cf =
      missing_authority.control_flow.functions.front();
  const auto missing_function_context =
      aarch64_codegen::make_function_lowering_context(
          missing_authority,
          missing_authority.target_profile,
          missing_function_cf);
  const auto missing_block_context =
      aarch64_codegen::make_block_lowering_context(
          missing_function_context,
          missing_function_cf.blocks.front(),
          0);
  aarch64_codegen::BlockScalarLoweringState missing_state;
  aarch64_codegen::record_emitted_scalar_register(
      missing_state,
      missing_param_name,
      aarch64_codegen::RegisterOperand{
          .reg = aarch64_abi::w_register(0),
          .role = aarch64_codegen::RegisterOperandRole::StoragePlan,
          .value_id = prepare::PreparedValueId{410},
          .value_name = missing_param_name,
          .expected_view = aarch64_abi::RegisterView::W,
      });
  if (aarch64_codegen::lower_fixed_formal_store_local_publication(
          missing_block_context,
          missing_authority.module.functions.front().blocks.front().insts.front(),
          0,
          missing_state)
          .has_value()) {
    return fail("expected fixed-formal store-local publication to fail closed without prepared formal/source-home authority");
  }
  return 0;
}

int variadic_entry_byval_aggregate_publishes_frame_slot_before_helper() {
  auto prepared = prepared_with_variadic_entry_byval_aggregate_stack_home();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context =
      aarch64_codegen::make_function_lowering_context(
          prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);

  if (!diagnostics.empty() || result.visited_operations != 1 ||
      !result.visited_terminator || result.emitted_instructions != 3 ||
      block.instructions.size() != 3) {
    return fail("expected byval aggregate publication, va_start helper, and return without diagnostics");
  }

  const auto* publication =
      std::get_if<aarch64_module::codegen::AssemblerInstructionRecord>(
          &block.instructions.front().target.payload);
  constexpr std::string_view expected_publication =
      "str x0, [sp, #32]\n"
      "strb w1, [sp, #40]";
  if (publication == nullptr ||
      block.instructions.front().target.family !=
          aarch64_module::codegen::InstructionFamily::Assembler ||
      block.instructions.front().target.selection.status !=
          aarch64_module::codegen::MachineNodeSelectionStatus::Selected ||
      !publication->has_inline_asm_payload ||
      publication->inline_asm_template != expected_publication) {
    return fail("expected byval aggregate frame-slot publication from ABI register lanes before va_start helper");
  }

  const auto* va_start =
      std::get_if<aarch64_module::codegen::CallInstructionRecord>(
          &block.instructions[1].target.payload);
  if (va_start == nullptr ||
      block.instructions[1].target.opcode !=
          aarch64_module::codegen::MachineOpcode::VariadicVaStart ||
      !va_start->variadic_va_start.has_value()) {
    return fail("expected inline va_start helper after byval aggregate publication");
  }
  if (!std::holds_alternative<aarch64_module::codegen::ReturnInstructionRecord>(
          block.instructions.back().target.payload)) {
    return fail("expected return terminator after byval aggregate publication route");
  }
  return 0;
}

