int block_dispatch_lowers_prepared_register_argument_move_before_direct_call() {
  auto prepared = prepared_with_direct_call_argument_register_move();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);

  if (result.visited_operations != 1 || !result.visited_terminator ||
      result.emitted_instructions != 3 || block.instructions.size() != 3 ||
      !diagnostics.empty()) {
    return fail("expected prepared direct call dispatch to emit arg move, call, and return");
  }

  const auto* move =
      std::get_if<aarch64_module::codegen::CallBoundaryMoveInstructionRecord>(
          &block.instructions[0].target.payload);
  const auto* call = std::get_if<aarch64_module::codegen::CallInstructionRecord>(
      &block.instructions[1].target.payload);
  if (move == nullptr ||
      block.instructions[0].target.family !=
          aarch64_module::codegen::InstructionFamily::CallBoundary ||
      block.instructions[0].target.opcode !=
          aarch64_module::codegen::MachineOpcode::CallBoundaryMove ||
      block.instructions[0].target.selection.status !=
          aarch64_module::codegen::MachineNodeSelectionStatus::Selected ||
      !move->source_register.has_value() || !move->destination_register.has_value() ||
      move->source_register->reg != aarch64_module::abi::x_register(2) ||
      move->destination_register->reg != aarch64_module::abi::x_register(0) ||
      move->source_bundle != &function_context.value_locations->move_bundles.front() ||
      move->source_move !=
          &function_context.value_locations->move_bundles.front().moves.front()) {
    return fail("expected prepared before-call register move to select x2 -> x0");
  }
  if (call == nullptr ||
      block.instructions[1].target.opcode !=
          aarch64_module::codegen::MachineOpcode::DirectCall ||
      !call->direct_callee.has_value() ||
      call->direct_callee_label != "actual_function") {
    return fail("expected direct call to remain after selected argument move");
  }
  if (!std::holds_alternative<aarch64_module::codegen::ReturnInstructionRecord>(
          block.instructions[2].target.payload)) {
    return fail("expected return terminator after selected argument move and call");
  }
  return 0;
}

int nested_call_argument_publishes_from_prior_preservation_home() {
  auto prepared = prepared_with_nested_call_preserved_argument_reuse();
  const auto& preserved =
      prepared.call_plans.functions.front().calls.front().preserved_values.front();
  auto& argument = prepared.call_plans.functions.front().calls.back().arguments.front();
  argument.source_selection =
      prepare::PreparedCallArgumentSourceSelection{
          .kind =
              prepare::PreparedCallArgumentSourceSelectionKind::PriorPreservation,
          .source_value_id = preserved.value_id,
          .source_value_name = preserved.value_name,
          .source_home_kind = prepare::PreparedValueHomeKind::Register,
          .preservation_route =
              prepare::PreparedCallPreservationRoute::CalleeSavedRegister,
          .preserved_register_name = preserved.register_name,
          .preserved_register_bank = preserved.register_bank,
          .preserved_register_contiguous_width = preserved.contiguous_width,
          .preserved_occupied_register_names = preserved.occupied_register_names,
          .preserved_register_placement =
              prepare::PreparedRegisterPlacement{
                  .bank = prepare::PreparedRegisterBank::Gpr,
                  .pool = prepare::PreparedRegisterSlotPool::CalleeSaved,
                  .slot_index = 1,
                  .contiguous_width = 1,
              },
      };

  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto prepared_lookups =
      prepare::make_prepared_function_lookups(prepared, function_cf);
  auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  attach_prepared_function_lookups(function_context, prepared_lookups);
  if (function_context.call_plans == nullptr ||
      function_context.call_plans->calls.size() != 2 ||
      function_context.call_plans->calls.front().preserved_values.empty() ||
      function_context.call_plans->calls.front().preserved_values.front().value_id !=
          prepare::PreparedValueId{141} ||
      function_context.call_plans->calls.back().arguments.empty() ||
      function_context.call_plans->calls.front().block_index != 0 ||
      function_context.call_plans->calls.back().block_index != 0 ||
      function_context.call_plans->calls.front().instruction_index != 0 ||
      function_context.call_plans->calls.back().instruction_index != 1 ||
      function_context.call_plans->calls.back().arguments.front().source_value_id !=
          std::optional<prepare::PreparedValueId>{prepare::PreparedValueId{141}}) {
    return fail("expected nested call fixture to carry prior preserved value");
  }
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);
  if (result.visited_operations != 2 || !result.visited_terminator ||
      result.emitted_instructions != 6 || block.instructions.size() != 6 ||
      !diagnostics.empty()) {
    const auto printed = print_route_block(function_cf.function_name, block);
    return fail("expected nested call dispatch to populate preserved home before call and reuse it later: emitted=" +
                std::to_string(result.emitted_instructions) +
                " block_size=" + std::to_string(block.instructions.size()) +
                " diagnostics=" + std::to_string(diagnostics.entries.size()) +
                (printed.ok ? " asm=" + printed.assembly
                            : " print=" + printed.diagnostic));
  }

  const auto* populate =
      std::get_if<aarch64_module::codegen::CallBoundaryMoveInstructionRecord>(
          &block.instructions[0].target.payload);
  if (populate == nullptr || !populate->source_register.has_value() ||
      !populate->destination_register.has_value() ||
      populate->source_register->reg != aarch64_module::abi::x_register(1) ||
      populate->destination_register->reg != aarch64_module::abi::x_register(20)) {
    const auto printed = print_route_block(function_cf.function_name, block);
    return fail("expected first call to populate preserved x20 home from original x1: " +
                (printed.ok ? printed.assembly : printed.diagnostic));
  }

  const auto* move =
      std::get_if<aarch64_module::codegen::CallBoundaryMoveInstructionRecord>(
          &block.instructions[3].target.payload);
  if (move == nullptr || !move->source_register.has_value() ||
      !move->destination_register.has_value() ||
      move->source_register->reg != aarch64_module::abi::x_register(20) ||
      move->destination_register->reg != aarch64_module::abi::x_register(0)) {
    const auto printed = print_route_block(function_cf.function_name, block);
    return fail("expected later call argument to publish from preserved x20 home: " +
                (printed.ok ? printed.assembly : printed.diagnostic));
  }

  const auto printed = print_route_block(function_cf.function_name, block);
  if (!printed.ok) {
    return fail("expected nested call route to print: " + printed.diagnostic);
  }
  const auto preserve_populate = printed.assembly.find("mov x20, x1");
  const auto first_call = printed.assembly.find("bl clobber_arg");
  const auto preserved_publish = printed.assembly.find("mov x0, x20", first_call);
  const auto stale_publish = printed.assembly.find("mov x0, x1", first_call);
  const auto second_call = printed.assembly.find("bl consume_arg", preserved_publish);
  if (preserve_populate == std::string::npos ||
      first_call == std::string::npos ||
      preserve_populate > first_call ||
      preserved_publish == std::string::npos ||
      second_call == std::string::npos ||
      (stale_publish != std::string::npos && stale_publish < second_call)) {
    return fail("expected preservation home to be populated before bl and reused after it: " +
                printed.assembly);
  }
  return 0;
}

