int block_dispatch_lowers_stack_published_f64_global_load_with_fpr_scratch() {
  auto prepared = prepared_with_stack_published_f64_global_load();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);

  if (result.visited_operations != 1 || !result.visited_terminator ||
      result.emitted_instructions != 2 || block.instructions.size() != 2 ||
      !diagnostics.empty()) {
    return fail("expected F64 global load to publish through a stack-backed FPR scratch: emitted=" +
                std::to_string(result.emitted_instructions) +
                " block_size=" + std::to_string(block.instructions.size()) +
                " diagnostics=" + std::to_string(diagnostics.entries.size()) +
                (diagnostics.entries.empty()
                     ? std::string{}
                     : " first=" + diagnostics.entries.front().message));
  }

  const auto* memory =
      std::get_if<aarch64_codegen::MemoryInstructionRecord>(
          &block.instructions.front().target.payload);
  if (memory == nullptr ||
      block.instructions.front().target.selection.status !=
          aarch64_codegen::MachineNodeSelectionStatus::Selected ||
      memory->memory_kind != aarch64_codegen::MemoryInstructionKind::Load ||
      memory->address.base_kind != aarch64_codegen::MemoryBaseKind::Symbol ||
      memory->address.size_bytes != 8 || memory->address.align_bytes != 8 ||
      memory->result_value_id != prepare::PreparedValueId{57} ||
      !memory->result_register.has_value() ||
      memory->result_register->reg != aarch64_abi::d_register(16) ||
      memory->result_stack_offset_bytes != std::optional<std::int64_t>{64}) {
    return fail("expected selected F64 global load to carry d16 stack publication facts");
  }

  const auto printed = print_route_block(function_cf.function_name, block);
  if (!printed.ok) {
    return fail("expected stack-published F64 global load route to print: " +
                printed.diagnostic);
  }
  const auto page = printed.assembly.find("adrp x9, global_double_lane");
  const auto low = printed.assembly.find("add x9, x9, :lo12:global_double_lane");
  const auto load = printed.assembly.find("ldr d16, [x9]");
  const auto store = printed.assembly.find("str d16, [sp, #64]");
  if (page == std::string::npos || low == std::string::npos ||
      load == std::string::npos || store == std::string::npos ||
      !(page < low && low < load && load < store)) {
    return fail("expected direct global F64 load to publish d16 into the prepared stack slot: " +
                printed.assembly);
  }

  return 0;
}

int block_dispatch_lowers_prepared_register_result_move_after_direct_call() {
  auto prepared = prepared_with_direct_call_result_register_move();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);

  if (result.visited_operations != 1 || !result.visited_terminator ||
      result.emitted_instructions != 3 || block.instructions.size() != 3 ||
      !diagnostics.empty()) {
    return fail("expected prepared direct call dispatch to emit call, result move, and return");
  }

  const auto* call = std::get_if<aarch64_module::codegen::CallInstructionRecord>(
      &block.instructions[0].target.payload);
  const auto* move =
      std::get_if<aarch64_module::codegen::CallBoundaryMoveInstructionRecord>(
          &block.instructions[1].target.payload);
  if (call == nullptr ||
      block.instructions[0].target.opcode !=
          aarch64_module::codegen::MachineOpcode::DirectCall ||
      !call->direct_callee.has_value() ||
      call->direct_callee_label != "actual_function") {
    return fail("expected direct call to remain before selected result move");
  }
  if (move == nullptr ||
      block.instructions[1].target.family !=
          aarch64_module::codegen::InstructionFamily::CallBoundary ||
      block.instructions[1].target.opcode !=
          aarch64_module::codegen::MachineOpcode::CallBoundaryMove ||
      block.instructions[1].target.selection.status !=
          aarch64_module::codegen::MachineNodeSelectionStatus::Selected ||
      move->phase != prepare::PreparedMovePhase::AfterCall ||
      !move->source_register.has_value() || !move->destination_register.has_value() ||
      move->source_register->reg != aarch64_module::abi::x_register(0) ||
      move->destination_register->reg != aarch64_module::abi::x_register(3) ||
      move->source_bundle != &function_context.value_locations->move_bundles.front() ||
      move->source_move !=
          &function_context.value_locations->move_bundles.front().moves.front()) {
    return fail("expected prepared after-call register result move to select x0 -> x3");
  }
  if (!std::holds_alternative<aarch64_module::codegen::ReturnInstructionRecord>(
          block.instructions[2].target.payload)) {
    return fail("expected return terminator after selected result move");
  }
  return 0;
}

int block_dispatch_lowers_prepared_hfa_result_lanes_from_distinct_fprs() {
  auto prepared = prepared_with_direct_hfa_call_result_lane_moves();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);

  if (result.visited_operations != 1 || !result.visited_terminator ||
      result.emitted_instructions != 4 || block.instructions.size() != 4 ||
      !diagnostics.empty()) {
    return fail("expected prepared HFA call dispatch to emit call, two lane moves, and return");
  }

  const auto* call = std::get_if<aarch64_module::codegen::CallInstructionRecord>(
      &block.instructions[0].target.payload);
  const auto* lane0 =
      std::get_if<aarch64_module::codegen::CallBoundaryMoveInstructionRecord>(
          &block.instructions[1].target.payload);
  const auto* lane1 =
      std::get_if<aarch64_module::codegen::CallBoundaryMoveInstructionRecord>(
          &block.instructions[2].target.payload);
  if (call == nullptr ||
      block.instructions[0].target.opcode !=
          aarch64_module::codegen::MachineOpcode::DirectCall ||
      !call->direct_callee.has_value() ||
      call->direct_callee_label != "actual_hfa_function") {
    return fail("expected direct HFA call to remain before selected result lane moves");
  }
  if (lane0 == nullptr || lane1 == nullptr ||
      lane0->phase != prepare::PreparedMovePhase::AfterCall ||
      lane1->phase != prepare::PreparedMovePhase::AfterCall ||
      !lane0->source_register.has_value() || !lane0->destination_register.has_value() ||
      !lane1->source_register.has_value() || !lane1->destination_register.has_value() ||
      lane0->source_register->reg != aarch64_module::abi::s_register(0) ||
      lane0->destination_register->reg != aarch64_module::abi::s_register(13) ||
      lane1->source_register->reg != aarch64_module::abi::s_register(1) ||
      lane1->destination_register->reg != aarch64_module::abi::s_register(14)) {
    return fail("expected HFA after-call lane moves to select s0->s13 and s1->s14");
  }
  if (!std::holds_alternative<aarch64_module::codegen::ReturnInstructionRecord>(
          block.instructions[3].target.payload)) {
    return fail("expected return terminator after selected HFA result lane moves");
  }
  return 0;
}

int block_dispatch_stores_hfa_call_result_lanes_from_abi_publication() {
  auto prepared = prepared_with_direct_hfa_call_result_lane_moves(true);
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);

  if (result.visited_operations != 3 || !result.visited_terminator ||
      result.emitted_instructions != 6 || block.instructions.size() != 6 ||
      !diagnostics.empty()) {
    std::string messages;
    for (const auto& entry : diagnostics.entries) {
      messages += " [";
      messages += entry.message;
      messages += "]";
    }
    return fail("expected HFA call, lane publications, two lane stores, and return; got visited=" +
                std::to_string(result.visited_operations) +
                " emitted=" + std::to_string(result.emitted_instructions) +
                " instructions=" + std::to_string(block.instructions.size()) +
                " diagnostics=" + std::to_string(diagnostics.entries.size()) +
                messages);
  }

  const auto* lane0_store =
      std::get_if<aarch64_module::codegen::MemoryInstructionRecord>(
          &block.instructions[3].target.payload);
  const auto* lane1_store =
      std::get_if<aarch64_module::codegen::MemoryInstructionRecord>(
          &block.instructions[4].target.payload);
  if (lane0_store == nullptr || lane1_store == nullptr ||
      lane0_store->memory_kind !=
          aarch64_module::codegen::MemoryInstructionKind::Store ||
      lane1_store->memory_kind !=
          aarch64_module::codegen::MemoryInstructionKind::Store ||
      !lane0_store->value.has_value() ||
      !lane1_store->value.has_value()) {
    return fail("expected selected HFA aggregate lane stores");
  }
  const auto* lane0_value =
      std::get_if<aarch64_module::codegen::RegisterOperand>(
          &lane0_store->value->payload);
  const auto* lane1_value =
      std::get_if<aarch64_module::codegen::RegisterOperand>(
          &lane1_store->value->payload);
  if (lane0_value == nullptr || lane1_value == nullptr ||
      lane0_value->reg != aarch64_module::abi::s_register(0) ||
      lane1_value->reg != aarch64_module::abi::s_register(1) ||
      lane0_value->prepared_bank != prepare::PreparedRegisterBank::Fpr ||
      lane1_value->prepared_bank != prepare::PreparedRegisterBank::Fpr ||
      lane0_value->role != aarch64_module::codegen::RegisterOperandRole::CallAbi ||
      lane1_value->role != aarch64_module::codegen::RegisterOperandRole::CallAbi) {
    return fail("expected HFA stores to consume ABI result lanes instead of stale FPR homes");
  }
  return 0;
}

