int block_dispatch_lowers_prepared_simple_integer_cast_with_result_register() {
  auto prepared = prepared_with_simple_integer_cast();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);

  if (!diagnostics.empty() || result.visited_operations != 1 ||
      result.emitted_instructions != 2 || block.instructions.size() != 2) {
    return fail("expected dispatch to select simple cast plus return");
  }
  const auto* scalar =
      std::get_if<aarch64_codegen::ScalarInstructionRecord>(
          &block.instructions.front().target.payload);
  if (scalar == nullptr ||
      block.instructions.front().target.selection.status !=
          aarch64_codegen::MachineNodeSelectionStatus::Selected ||
      !scalar->scalar_cast.has_value() || scalar->scalar_alu.has_value() ||
      scalar->source_cast_opcode != bir::CastOpcode::SExt ||
      scalar->result_value_id != prepare::PreparedValueId{21} ||
      !scalar->result_register.has_value() ||
      scalar->result_register->occupied_registers.empty() ||
      scalar->result_register->occupied_registers.front() != "x0") {
    return fail("expected selected simple cast to preserve destination register facts");
  }
  const auto* source =
      std::get_if<aarch64_codegen::RegisterOperand>(
          &scalar->scalar_cast->source.payload);
  if (source == nullptr || source->value_id != prepare::PreparedValueId{20} ||
      source->occupied_registers.empty() || source->occupied_registers.front() != "w1" ||
      block.instructions.front().target.defs.empty() ||
      block.instructions.front().target.defs.front().kind !=
          aarch64_codegen::MachineEffectResourceKind::Register) {
    return fail("expected selected simple cast to preserve source register and def facts");
  }

  return 0;
}

int block_dispatch_publishes_prepared_consumer_register_for_stack_source_casts() {
  struct Case {
    bir::CastOpcode opcode;
    bir::TypeKind source_type;
    bir::TypeKind result_type;
    std::string_view expected_load;
    std::string_view expected_assembly;
  };
  const Case cases[] = {
      {bir::CastOpcode::SExt, bir::TypeKind::I32, bir::TypeKind::I64,
       "ldr w0, [sp, #16]", "sxtw x0, w0"},
      {bir::CastOpcode::SExt, bir::TypeKind::I16, bir::TypeKind::I32,
       "ldrh w0, [sp, #16]", "sxth w0, w0"},
      {bir::CastOpcode::ZExt, bir::TypeKind::I8, bir::TypeKind::I32,
       "ldrb w0, [sp, #16]", "ubfx x0, x0, #0, #8"},
  };

  for (const auto& test_case : cases) {
    auto prepared = prepared_with_simple_integer_cast(test_case.opcode,
                                                     test_case.source_type,
                                                     test_case.result_type,
                                                     true,
                                                     true);
    const auto& function_cf = prepared.control_flow.functions.front();
    const auto& block_cf = function_cf.blocks.front();
    auto function_context = aarch64_codegen::make_function_lowering_context(
        prepared, prepared.target_profile, function_cf);
    const auto prepared_lookups =
        prepare::make_prepared_function_lookups(prepared, function_cf);
    attach_prepared_function_lookups(function_context, prepared_lookups);
    const auto block_context =
        aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

    aarch64_module::MachineBlock block;
    aarch64_module::ModuleLoweringDiagnostics diagnostics;
    const auto result =
        aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);

    if (!diagnostics.empty() || result.visited_operations != 1 ||
        result.emitted_instructions != 2 || block.instructions.size() != 2) {
      return fail("expected stack-sourced simple cast publication plus return");
    }
    const auto* assembler =
        std::get_if<aarch64_codegen::AssemblerInstructionRecord>(
            &block.instructions.front().target.payload);
    if (assembler == nullptr ||
        block.instructions.front().target.family !=
            aarch64_codegen::InstructionFamily::Assembler ||
        block.instructions.front().target.selection.status !=
            aarch64_codegen::MachineNodeSelectionStatus::Selected ||
        !assembler->has_inline_asm_payload) {
      return fail("expected direct stack-sourced cast to preserve assembler publication");
    }

    const auto printed = print_route_block(function_cf.function_name, block);
    if (!printed.ok ||
        printed.assembly.find(test_case.expected_load) == std::string::npos ||
        printed.assembly.find(test_case.expected_assembly) == std::string::npos) {
      return fail("expected direct stack-sourced cast to load and print from the consumer register");
    }
  }

  return 0;
}

int block_dispatch_publishes_select_stack_source_cast_from_prepared_consumer_move() {
  auto prepared = prepared_with_select_produced_stack_source_cast();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);

  if (result.visited_operations != 2 || result.emitted_instructions != 2 ||
      block.instructions.size() != 2) {
    return fail("expected selected stack-source cast plus return");
  }
  const auto* scalar =
      std::get_if<aarch64_codegen::ScalarInstructionRecord>(
          &block.instructions.front().target.payload);
  if (scalar == nullptr ||
      !block.instructions.front().origin.has_value() ||
      block.instructions.front().origin->instruction_index != 1 ||
      block.instructions.front().target.selection.status !=
          aarch64_codegen::MachineNodeSelectionStatus::Selected ||
      !scalar->scalar_cast.has_value() || scalar->source_cast_opcode != bir::CastOpcode::SExt ||
      scalar->result_value_id != prepare::PreparedValueId{31} ||
      !scalar->result_register.has_value() ||
      scalar->result_register->occupied_registers.empty() ||
      scalar->result_register->occupied_registers.front() != "w0") {
    return fail("expected selected scalar cast from select-produced stack source");
  }

  const auto* source =
      std::get_if<aarch64_codegen::RegisterOperand>(
          &scalar->scalar_cast->source.payload);
  if (scalar->scalar_cast->source.kind != aarch64_codegen::OperandKind::Register ||
      source == nullptr || source->value_id != prepare::PreparedValueId{30} ||
      source->value_name != prepared.names.value_names.intern("%selected") ||
      source->occupied_registers.empty() || source->occupied_registers.front() != "w0" ||
      scalar->inputs.size() != 1 ||
      scalar->inputs.front().kind != aarch64_codegen::OperandKind::Register) {
    return fail("expected selected scalar cast to publish prepared consumer register source");
  }

  const auto printed = print_route_block(function_cf.function_name, block);
  if (!printed.ok ||
      printed.assembly.find("sxth w0, w0") == std::string::npos ||
      printed.assembly.find("scalar cast node requires a structured register source operand") !=
          std::string::npos) {
    return fail("expected selected scalar cast to print from structured register source");
  }

  return 0;
}

int block_dispatch_publishes_stack_homed_scalar_select_before_store_consumer() {
  auto prepared = prepared_with_stack_published_i16_select_store();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);

  if (!diagnostics.empty() || result.visited_operations != 2 ||
      result.emitted_instructions != 3 || block.instructions.size() != 3) {
    return fail("expected stack-homed scalar select, store consumer, and return: visited=" +
                std::to_string(result.visited_operations) +
                " emitted=" + std::to_string(result.emitted_instructions) +
                " block_size=" + std::to_string(block.instructions.size()) +
                " diagnostics=" + std::to_string(diagnostics.entries.size()) +
                (diagnostics.entries.empty()
                     ? std::string{}
                     : " first=" + diagnostics.entries.front().message));
  }
  const auto* select_publication =
      std::get_if<aarch64_codegen::AssemblerInstructionRecord>(
          &block.instructions.front().target.payload);
  if (select_publication == nullptr ||
      block.instructions.front().target.family !=
          aarch64_codegen::InstructionFamily::Assembler ||
      block.instructions.front().target.selection.status !=
          aarch64_codegen::MachineNodeSelectionStatus::Selected ||
      !select_publication->has_inline_asm_payload) {
    return fail("expected scalar select to lower through selected assembler publication");
  }

  const auto printed = print_route_block(function_cf.function_name, block);
  if (!printed.ok) {
    return fail("expected stack-homed scalar select store route to print: " +
                printed.diagnostic);
  }
  const auto csel = printed.assembly.find("csel ");
  const auto publication = printed.assembly.find("strh ", csel);
  const auto consumer_reload = printed.assembly.find("ldrh ", publication);
  const auto destination_store = printed.assembly.find("strh ", consumer_reload);
  if (csel == std::string::npos || publication == std::string::npos ||
      consumer_reload == std::string::npos ||
      destination_store == std::string::npos ||
      printed.assembly.find("[sp, #16]", publication) == std::string::npos ||
      printed.assembly.find("[sp, #24]", destination_store) == std::string::npos) {
    return fail("expected scalar select to publish its stack home before the store consumer reloads it: " +
                printed.assembly);
  }

  return 0;
}

