int block_dispatch_publishes_computed_address_to_pointer_local_before_reload() {
  auto prepared = prepared_with_pointer_local_computed_address_reassignment();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);
  if (!diagnostics.empty() || result.visited_operations != 4 ||
      block.instructions.size() < 5) {
    const std::string diagnostic =
        diagnostics.empty() ? std::string{} : " first=" + diagnostics.entries.front().message;
    return fail("expected pointer-local computed address publication before reload: ops=" +
                std::to_string(result.visited_operations) +
                " emitted=" + std::to_string(result.emitted_instructions) +
                " instructions=" + std::to_string(block.instructions.size()) +
                " diagnostics=" + std::to_string(diagnostics.entries.size()) +
                diagnostic);
  }

  const auto printed = print_route_block(function_cf.function_name, block);
  if (!printed.ok) {
    return fail("expected pointer-local computed address route to print: " +
                printed.diagnostic);
  }
  const auto materialize = printed.assembly.find("adrp ");
  const auto symbol = printed.assembly.find("global_pair+4");
  const auto publish = printed.assembly.find("str x9, [sp, #16]");
  const auto reload = printed.assembly.find("ldr x13, [sp, #16]");
  const auto dereference = printed.assembly.find("ldr w14, [x13]");
  if (materialize == std::string::npos ||
      symbol == std::string::npos ||
      publish == std::string::npos ||
      reload == std::string::npos ||
      dereference == std::string::npos ||
      !(materialize < publish && publish < reload && reload < dereference)) {
    return fail("expected computed global subobject address to be stored to pointer local before dereference: " +
                printed.assembly);
  }
  return 0;
}

int block_dispatch_keeps_pointer_index_and_scale_registers_distinct() {
  auto prepared = prepared_with_pointer_index_byte_offset_scale();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);
  if (!diagnostics.empty() || result.visited_operations != 1 ||
      block.instructions.empty()) {
    const std::string diagnostic =
        diagnostics.empty() ? std::string{} : " first=" + diagnostics.entries.front().message;
    return fail("expected pointer byte-offset scale multiply to lower: ops=" +
                std::to_string(result.visited_operations) +
                " instructions=" + std::to_string(block.instructions.size()) +
                " diagnostics=" + std::to_string(diagnostics.entries.size()) +
                diagnostic);
  }

  const auto printed = print_route_block(function_cf.function_name, block);
  if (!printed.ok) {
    return fail("expected pointer byte-offset scale route to print: " +
                printed.diagnostic);
  }
  const auto load_index = printed.assembly.find("ldr x9, [sp, #40]");
  const auto scale = printed.assembly.find("lsl x9, x9, #2", load_index);
  if (load_index == std::string::npos ||
      scale == std::string::npos ||
      printed.assembly.find("mov x9, #4") != std::string::npos ||
      printed.assembly.find("mul x9, x9, x9") != std::string::npos) {
    return fail("expected pointer byte-offset scale to preserve index carrier: " +
                printed.assembly);
  }
  return 0;
}

int block_dispatch_preserves_pointer_base_for_scaled_index_load_publication() {
  auto prepared = prepared_with_pointer_base_scaled_index_load();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  const auto prepared_lookups =
      prepare::make_prepared_function_lookups(prepared, function_cf);
  attach_prepared_function_lookups(function_context, prepared_lookups);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);
  if (!diagnostics.empty() || result.visited_operations != 4 ||
      !result.visited_terminator || block.instructions.size() < 5) {
    const std::string diagnostic =
        diagnostics.empty() ? std::string{} : " first=" + diagnostics.entries.front().message;
    return fail("expected pointer-derived scaled load publication to lower: ops=" +
                std::to_string(result.visited_operations) +
                " term=" + std::to_string(result.visited_terminator) +
                " instructions=" + std::to_string(block.instructions.size()) +
                " diagnostics=" + std::to_string(diagnostics.entries.size()) +
                diagnostic);
  }

  const auto printed = print_route_block(function_cf.function_name, block);
  if (!printed.ok) {
    return fail("expected pointer-derived scaled load route to print: " +
                printed.diagnostic);
  }
  const auto base = printed.assembly.find("mov x9, x0");
  const auto index = printed.assembly.find("ldr w10, [sp, #36]", base);
  const auto extend = printed.assembly.find("sxtw x10, w10", index);
  const auto scale = printed.assembly.find("lsl x10, x10, #2", extend);
  const auto address = printed.assembly.find("add x9, x9, x10", scale);
  const auto load = printed.assembly.find("ldr w0, [x9]", address);
  if (base == std::string::npos ||
      index == std::string::npos ||
      extend == std::string::npos ||
      scale == std::string::npos ||
      address == std::string::npos ||
      load == std::string::npos ||
      printed.assembly.find("mov x9, #4") != std::string::npos) {
    return fail("expected pointer base to survive scaled index materialization before load: " +
                printed.assembly);
  }
  return 0;
}

int block_dispatch_publishes_stack_homed_pointer_value_load_chain() {
  auto prepared = prepared_with_stack_homed_pointer_value_load_chain();
  const auto& function_cf = prepared.control_flow.functions.front();
  const auto& block_cf = function_cf.blocks.front();
  const auto function_context = aarch64_codegen::make_function_lowering_context(
      prepared, prepared.target_profile, function_cf);
  const auto block_context =
      aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

  aarch64_module::MachineBlock block;
  aarch64_module::ModuleLoweringDiagnostics diagnostics;
  const auto result =
      aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);
  if (!diagnostics.empty() || result.visited_operations != 3 ||
      !result.visited_terminator || block.instructions.size() < 4) {
    const std::string diagnostic =
        diagnostics.empty() ? std::string{} : " first=" + diagnostics.entries.front().message;
    return fail("expected pointer-value load chain to lower without diagnostics: ops=" +
                std::to_string(result.visited_operations) +
                " term=" + std::to_string(result.visited_terminator) +
                " emitted=" + std::to_string(block.instructions.size()) +
                " diagnostics=" + std::to_string(diagnostics.entries.size()) +
                diagnostic);
  }

  const auto printed = print_route_block(function_cf.function_name, block);
  if (!printed.ok) {
    return fail("expected pointer-value load chain route to print: " +
                printed.diagnostic);
  }
  const auto first_pointer_load = printed.assembly.find("ldr x21, [sp, #16]");
  const auto stack_publication = printed.assembly.find("str x9, [sp, #40]");
  const auto pointer_reload = printed.assembly.find("ldr x9, [sp, #40]");
  const auto final_pointee_load = printed.assembly.find("ldr w21, [x9]");
  const auto return_move = printed.assembly.find("mov x0, x21");
  if (first_pointer_load == std::string::npos ||
      stack_publication == std::string::npos ||
      pointer_reload == std::string::npos ||
      final_pointee_load == std::string::npos ||
      return_move == std::string::npos ||
      !(first_pointer_load < stack_publication &&
        stack_publication < pointer_reload &&
        pointer_reload < final_pointee_load &&
        final_pointee_load < return_move)) {
    return fail("expected stack-homed pointer value to publish before final pointee return: " +
                printed.assembly);
  }
  return 0;
}

int block_dispatch_reports_missing_store_source_authority_and_unsupported_base() {
  {
    auto prepared = prepared_with_store(StoreDispatchFixtureKind::FrameSlot, false);
    const auto& function_cf = prepared.control_flow.functions.front();
    const auto& block_cf = function_cf.blocks.front();
    const auto function_context = aarch64_codegen::make_function_lowering_context(
        prepared, prepared.target_profile, function_cf);
    const auto block_context =
        aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

    aarch64_module::MachineBlock block;
    aarch64_module::ModuleLoweringDiagnostics diagnostics;
    const auto result =
        aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);
    if (result.visited_operations != 1 || result.emitted_instructions != 1 ||
        block.instructions.size() != 1 || diagnostics.entries.size() != 1 ||
        diagnostics.entries.front().message.find("missing_stored_storage") ==
            std::string::npos) {
      return fail("expected missing stored-source storage diagnostic");
    }
  }

  {
    auto prepared = prepared_with_store(StoreDispatchFixtureKind::StringConstant);
    const auto& function_cf = prepared.control_flow.functions.front();
    const auto& block_cf = function_cf.blocks.front();
    const auto function_context = aarch64_codegen::make_function_lowering_context(
        prepared, prepared.target_profile, function_cf);
    const auto block_context =
        aarch64_codegen::make_block_lowering_context(function_context, block_cf, 0);

    aarch64_module::MachineBlock block;
    aarch64_module::ModuleLoweringDiagnostics diagnostics;
    const auto result =
        aarch64_codegen::dispatch_prepared_block(block_context, block, diagnostics);
    if (result.visited_operations != 1 || result.emitted_instructions != 1 ||
        block.instructions.size() != 1 || diagnostics.entries.size() != 1 ||
        diagnostics.entries.front().message.find("unsupported_base") == std::string::npos) {
      return fail("expected unsupported string-constant store diagnostic");
    }
  }

  return 0;
}

